import { Pipe, PipeTransform, inject } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

/**
 * Renders author-supplied HTML *without* Angular's sanitizer stripping it.
 *
 * Angular's default [innerHTML] binding removes <iframe>, inline event handlers,
 * and other "unsafe" markup — which silently drops embeds like Vimeo/YouTube.
 * This pipe bypasses that so rich page content renders as authored.
 *
 * ⚠️ SECURITY: bypassing sanitization trusts the HTML. That's acceptable here
 * because page/syllabus content is authored only by Platform Admins / Instructors.
 * If page authoring is ever opened to untrusted users, sanitize server-side
 * (or with DOMPurify + an iframe allowlist) instead of trusting blindly.
 */
@Pipe({ name: 'safeHtml', standalone: true })
export class SafeHtmlPipe implements PipeTransform {
  private sanitizer = inject(DomSanitizer);

  transform(value: string | null | undefined): SafeHtml {
    return this.sanitizer.bypassSecurityTrustHtml(value ?? '');
  }
}
